# ── Встроенные шрифты (Cyrillic+Latin subset DejaVu Sans) ─────────────────────
# Закодированы в base64 — не требуют системных шрифтов (работает на Render, VPS и т.д.)
import base64 as _b64, tempfile as _tmp, os as _os

_FONT_REG_B64  = ""
_FONT_BOLD_B64 = ""

def _extract_fonts():
    """Распаковывает шрифты во временную папку при первом вызове."""
    tmp = _tmp.gettempdir()
    reg_path  = _os.path.join(tmp, 'izlom_font_reg.ttf')
    bold_path = _os.path.join(tmp, 'izlom_font_bold.ttf')
    if not _os.path.exists(reg_path):
        with open(reg_path, 'wb') as f:
            f.write(_b64.b64decode(_FONT_REG_B64))
    if not _os.path.exists(bold_path):
        with open(bold_path, 'wb') as f:
            f.write(_b64.b64decode(_FONT_BOLD_B64))
    return reg_path, bold_path

_FONT_REG_PATH, _FONT_BOLD_PATH = _extract_fonts()
