def is_subscribed_to_channel(user_id: int) -> bool:
    try:
        member = bot.get_chat_member(REQUIRED_CHANNEL, user_id)
        return member.status in ('member', 'administrator', 'creator')
    except Exception as e:
        logger.error(f"Ошибка проверки подписки {user_id}: {e}")
        return False


def channel_check_markup():
    markup = types.InlineKeyboardMarkup(row_width=1)
    markup.add(
        types.InlineKeyboardButton("📢 Подписаться на канал", url=REQUIRED_CHANNEL_URL),
        types.InlineKeyboardButton("✅ Я подписался", callback_data="check_subscription"),
    )
    return markup


def require_subscription(func):
    def wrapper(message_or_call, *args, **kwargs):
        if isinstance(message_or_call, types.CallbackQuery):
            user_id = message_or_call.from_user.id
            chat_id = message_or_call.message.chat.id
        else:
            user_id = message_or_call.from_user.id
            chat_id = message_or_call.chat.id
        if not is_subscribed_to_channel(user_id):
            markup = channel_check_markup()
            bot.send_message(
                chat_id,
                "📢 *Для использования бота необходимо подписаться на наш канал!*\n\n"
                f"Подпишитесь на {REQUIRED_CHANNEL} и нажмите «✅ Я подписался».",
                parse_mode='Markdown', reply_markup=markup
            )
            if isinstance(message_or_call, types.CallbackQuery):
                bot.answer_callback_query(message_or_call.id)
            return
        return func(message_or_call, *args, **kwargs)
    return wrapper


def has_accepted_terms(user_id: int) -> bool:
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT terms_accepted FROM users WHERE telegram_id=?", (user_id,))
    row = c.fetchone()
    conn.close()
    return bool(row and row[0])


