def generate_receipt_pdf(user_id: int, plan_name: str, amount: int, label: str,
                          end_date: datetime, payment_type: str = "Банковская карта") -> BytesIO:
    import math

    # Шрифты с кириллицей — встроены в код, работают везде без установки
    if not getattr(generate_receipt_pdf, '_fonts_ok', False):
        try:
            pdfmetrics.registerFont(TTFont('DVSans',      _FONT_REG_PATH))
            pdfmetrics.registerFont(TTFont('DVSans-Bold', _FONT_BOLD_PATH))
            generate_receipt_pdf._fonts_ok = True
        except Exception as _e:
            logger.warning(f"Ошибка загрузки шрифта: {_e}")
            generate_receipt_pdf._fonts_ok = False

    FR  = 'DVSans' if getattr(generate_receipt_pdf, '_fonts_ok', False) else 'Helvetica'
    FB  = 'DVSans-Bold' if getattr(generate_receipt_pdf, '_fonts_ok', False) else 'Helvetica-Bold'

    buf = BytesIO()
    now = datetime.now()
    receipt_id = f"RCP-{label[-8:].upper()}"
    W, H = A4
    pw, ph = int(W), int(H)

    def hc(h):
        h = h.lstrip('#')
        return colors.Color(int(h[0:2],16)/255, int(h[2:4],16)/255, int(h[4:6],16)/255)

    def pil_ir(img):
        b = BytesIO(); img.save(b, 'PNG'); b.seek(0); return ImageReader(b)

    def grad(w, h, stops):
        img = Image.new('RGB', (w, h)); d = ImageDraw.Draw(img)
        for y in range(h):
            t = y / max(h-1,1)
            for i in range(len(stops)-1):
                t0,c0 = stops[i]; t1,c1 = stops[i+1]
                if t0 <= t <= t1:
                    s = (t-t0)/(t1-t0)
                    d.line([(0,y),(w,y)], fill=tuple(int(c0[j]+s*(c1[j]-c0[j])) for j in range(3)))
                    break
        return img

    def glow(w, h, cx, cy, r, col, amax=80):
        img = Image.new('RGBA', (w, h), (0,0,0,0)); arr = img.load()
        for y in range(h):
            for x in range(w):
                d = math.sqrt((x-cx)**2+(y-cy)**2)
                if d < r:
                    arr[x,y] = (*col, int(amax*(1-d/r)**2))
        return img

    cv = canvas.Canvas(buf, pagesize=A4)

    # Фон
    cv.drawImage(pil_ir(grad(pw,ph,[(0,(4,6,14)),(0.5,(8,12,28)),(1,(4,8,20))])), 0, 0, W, H)

    # Светящиеся орбы
    for gx,gy,gr,gc,ga in [
        (int(pw*.15),int(ph*.2),180,(0,180,255),55),
        (int(pw*.85),int(ph*.75),200,(120,40,220),50),
        (int(pw*.5),int(ph*.5),140,(0,220,180),22),
    ]:
        cv.drawImage(pil_ir(glow(pw,ph,gx,gy,gr,gc,ga)), 0, 0, W, H, mask='auto')

    # Сетка
    gi = Image.new('RGBA',(pw,ph),(0,0,0,0)); gd = ImageDraw.Draw(gi)
    for x in range(0,pw,28): gd.line([(x,0),(x,ph)],fill=(0,212,255,10))
    for y in range(0,ph,28): gd.line([(0,y),(pw,y)],fill=(0,212,255,10))
    cv.drawImage(pil_ir(gi), 0, 0, W, H, mask='auto')

    # Полосы сверху/снизу
    cv.drawImage(pil_ir(grad(pw,10,[(0,(0,212,255)),(1,(124,58,237))])), 0, H-10, W, 10)
    cv.drawImage(pil_ir(grad(pw,6,[(0,(124,58,237)),(1,(0,212,255))])), 0, 0, W, 6)

    # Карточка
    mx=22*mm; cx_=mx; cw=W-2*mx; cy_=52*mm; ch=H-52*mm-28*mm
    sh = Image.new('RGBA',(pw,ph),(0,0,0,0)); sd=ImageDraw.Draw(sh)
    py_y=ph-int(cy_)-int(ch)
    for i in range(10,0,-1):
        sd.rounded_rectangle([int(cx_)-i,py_y-i,int(cx_+cw)+i,py_y+int(ch)+i],radius=14,fill=(0,0,0,int(70*(i/10)**2)))
    sh=sh.filter(ImageFilter.GaussianBlur(5)); cv.drawImage(pil_ir(sh), 0, 0, W, H, mask='auto')
    ci=Image.new('RGBA',(pw,ph),(0,0,0,0)); cd=ImageDraw.Draw(ci)
    cd.rounded_rectangle([int(cx_),py_y,int(cx_+cw),py_y+int(ch)],radius=14,fill=(10,18,38,235),outline=(0,212,255,45),width=1)
    cv.drawImage(pil_ir(ci), 0, 0, W, H, mask='auto')

    # Светящаяся линия сверху карточки
    gl=Image.new('RGBA',(int(cw),3),(0,0,0,0)); gld=ImageDraw.Draw(gl)
    for xi in range(int(cw)):
        t=xi/int(cw)
        gld.line([(xi,0),(xi,2)],fill=(int(t*124),int(212+t*(58-212)),int(255+t*(237-255)),int(160*math.sin(math.pi*t))))
    cv.drawImage(pil_ir(gl), cx_, H-cy_-ch, cw, 2, mask='auto')

    # Логотип — без круга, молнии по бокам
    ly=H-26*mm

    # Текст IZLOM VPN
    cv.setFont(FB,24); cv.setFillColor(hc('#001428')); cv.drawCentredString(W/2+1,ly-0.5*mm,'IZLOM VPN')
    cv.setFillColor(hc('#00d4ff')); cv.drawCentredString(W/2,ly,'IZLOM VPN')

    # Молнии по бокам
    from reportlab.pdfbase import pdfmetrics as _pm
    txt_w = _pm.stringWidth('IZLOM VPN', FB, 24)
    gap = 4*mm

    def draw_bolt(size=22):
        img = Image.new('RGBA', (size, size), (0,0,0,0))
        d = ImageDraw.Draw(img)
        s = size
        pts = [(int(s*0.62),0),(int(s*0.28),int(s*0.52)),(int(s*0.50),int(s*0.48)),
               (int(s*0.38),s),(int(s*0.72),int(s*0.48)),(int(s*0.50),int(s*0.52))]
        for offset in range(4,0,-1):
            d.polygon(pts, fill=(0,212,255,int(60/offset)))
        d.polygon(pts, fill=(0,212,255,255))
        d.polygon(pts, outline=(200,245,255,180))
        return img

    bsz = int(6*mm)
    bolt = draw_bolt(bsz)
    bolt_r = bolt.transpose(Image.FLIP_LEFT_RIGHT)

    lx = W/2 - txt_w/2 - gap - bsz
    cv.drawImage(pil_ir(bolt),   lx, ly - bsz*0.3, bsz, bsz, mask='auto')
    rx = W/2 + txt_w/2 + gap
    cv.drawImage(pil_ir(bolt_r), rx, ly - bsz*0.3, bsz, bsz, mask='auto')

    cv.setFont(FR,8); cv.setFillColor(hc('#475569')); cv.drawCentredString(W/2,ly-6*mm,'ПЛАТЁЖНЫЙ ЧЕК')

    # Бейдж с номером чека
    py=H-47*mm; pw_=72*mm; px=(W-pw_)/2
    pi=Image.new('RGBA',(pw,ph),(0,0,0,0)); pd=ImageDraw.Draw(pi)
    py_p=ph-int(py)-int(7*mm)
    pd.rounded_rectangle([int(px),py_p,int(px+pw_),py_p+int(7*mm)],radius=int(3.5*mm),fill=(0,35,65,210),outline=(0,212,255,190),width=1)
    cv.drawImage(pil_ir(pi), 0, 0, W, H, mask='auto')
    cv.setFont(FB,9); cv.setFillColor(hc('#00d4ff')); cv.drawCentredString(W/2,py+1.8*mm,receipt_id)

    # Строки данных
    rows = [
        ('Дата оплаты',   now.strftime('%d.%m.%Y   %H:%M'), '#cbd5e1', False),
        ('Услуга',         f'VPN \u00ab{plan_name}\u00bb',   '#e2e8f0', False),
        ('Способ оплаты', payment_type,                       '#e2e8f0', False),
        ('Статус',        'ОПЛАЧЕНО',                         '#10b981', True),
        ('Активен до',    end_date.strftime('%d.%m.%Y'),      '#10b981', False),
        ('ID клиента',    str(user_id),                       '#64748b', False),
    ]
    rsy=H-57*mm; rh=10.8*mm; rp=9*mm
    for i,(lbl,val,col,bold) in enumerate(rows):
        y=rsy-i*rh
        if i%2==0:
            rb=Image.new('RGBA',(pw,ph),(0,0,0,0)); rb_d=ImageDraw.Draw(rb)
            py_r=ph-int(y)-int(rh-1.5*mm)
            rb_d.rectangle([int(cx_+6*mm),py_r,int(cx_+cw-6*mm),py_r+int(rh-2*mm)],fill=(0,212,255,7))
            cv.drawImage(pil_ir(rb), 0, 0, W, H, mask='auto')
        cv.setFont(FR,8.5); cv.setFillColor(hc('#64748b')); cv.drawString(cx_+rp,y+1*mm,lbl)
        cv.setFont(FB if bold else FR,9); cv.setFillColor(hc(col)); cv.drawRightString(cx_+cw-rp,y+1*mm,val)
        if i<len(rows)-1:
            sep=Image.new('RGBA',(pw,1),(0,0,0,0)); sp_d=ImageDraw.Draw(sep)
            for xi in range(int(cx_+rp),int(cx_+cw-rp)):
                t=(xi-(cx_+rp))/(cw-2*rp)
                sp_d.point([(xi,0)],fill=(0,212,255,int(35*math.sin(math.pi*t))))
            cv.drawImage(pil_ir(sep), 0, y-2.5*mm, W, 1, mask='auto')

    # Блок суммы
    ay=cy_+16*mm; ah=22*mm; ax=cx_+10*mm; aw=cw-20*mm
    ab=grad(int(aw),int(ah),[(0,(0,25,55)),(0.5,(0,18,45)),(1,(8,0,38))])
    ap=Image.new('RGBA',(int(aw),int(ah)),(0,0,0,0)); ap.paste(ab)
    ImageDraw.Draw(ap).rounded_rectangle([0,0,int(aw)-1,int(ah)-1],radius=8,outline=(0,212,255,210),width=2)
    cv.drawImage(pil_ir(ap), ax, ay-4*mm, aw, ah, mask='auto')
    cv.setFont(FR,7.5); cv.setFillColor(hc('#475569')); cv.drawCentredString(W/2,ay+13*mm,'И Т О Г О   К   О П Л А Т Е')
    cv.setFont(FB,28); cv.setFillColor(hc('#001428')); cv.drawCentredString(W/2+1,ay+4.5*mm,f'{amount} RUB')
    cv.setFillColor(hc('#00d4ff')); cv.drawCentredString(W/2,ay+5*mm,f'{amount} RUB')

    # Галочка
    st=Image.new('RGBA',(64,64),(0,0,0,0)); std=ImageDraw.Draw(st)
    for r in range(30,26,-1): std.ellipse([32-r,32-r,32+r,32+r],outline=(16,185,129,int(160*(r-26)/4)),width=1)
    std.ellipse([4,4,60,60],outline=(16,185,129,220),width=2)
    std.line([(16,32),(26,42),(48,20)],fill=(16,185,129,255),width=3)
    cv.drawImage(pil_ir(st), cx_+cw-22*mm, ay+2*mm, 14*mm, 14*mm, mask='auto')

    # Угловые скобки
    cl=5*mm; cv.setStrokeColor(hc('#00d4ff')); cv.setLineWidth(1.5)
    x1,x2=cx_+4*mm,cx_+cw-4*mm; y1,y2=H-cy_-ch+4*mm,cy_+4*mm
    cv.line(x1,y1+cl,x1,y1); cv.line(x1,y1,x1+cl,y1)
    cv.line(x2-cl,y1,x2,y1); cv.line(x2,y1,x2,y1+cl)
    cv.line(x1,y2,x1,y2+cl); cv.line(x1,y2,x1+cl,y2)
    cv.line(x2-cl,y2,x2,y2); cv.line(x2,y2,x2,y2+cl)

    # Футер
    cv.setFont(FR,7.5); cv.setFillColor(hc('#334155'))
    cv.drawCentredString(W/2,16*mm,'Поддержка: @izlomc_support   ·   izlomc.ru   ·   @izlomc_bot')
    cv.setFillColor(hc('#1e293b'))
    cv.drawCentredString(W/2,11*mm,'Данный документ является подтверждением оплаты услуг Izlom VPN')

    cv.save(); buf.seek(0)
    return buf


def send_receipt_pdf(chat_id: int, user_id: int, plan_name: str, amount: int,
                     label: str, end_date: datetime, payment_type: str = "Банковская карта"):
    try:
        pdf_buf = generate_receipt_pdf(user_id, plan_name, amount, label, end_date, payment_type)
        receipt_id = f"RCP-{label[-8:].upper()}"
        bot.send_document(
            chat_id,
            pdf_buf,
            visible_file_name=f"receipt_{receipt_id}.pdf",
            caption=f"🧾 Ваш чек об оплате — {receipt_id}",
        )
    except Exception as e:
        logger.error(f"Ошибка генерации PDF-чека: {e}")


def init_db():
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    # DROP TABLE убраны — данные сохраняются при перезапуске
    c.execute('''CREATE TABLE IF NOT EXISTS plans
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  name TEXT UNIQUE, price INTEGER, devices INTEGER,
                  features TEXT, server_count INTEGER DEFAULT 10)''')
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY,
                  telegram_id INTEGER UNIQUE, username TEXT, first_name TEXT,
                  email TEXT, plan_id INTEGER, subscription_end TIMESTAMP,
                  subscription_key TEXT, subscription_url TEXT,
                  balance INTEGER DEFAULT 0, promo_balance INTEGER DEFAULT 0,
                  referral_code TEXT UNIQUE, referred_by INTEGER,
                  terms_accepted INTEGER DEFAULT 0,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  FOREIGN KEY(referred_by) REFERENCES users(telegram_id))''')
    c.execute('''CREATE TABLE IF NOT EXISTS payments
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  user_id INTEGER, plan_id INTEGER, amount INTEGER,
                  payment_id TEXT UNIQUE, label TEXT UNIQUE,
                  status TEXT DEFAULT 'pending', payment_type TEXT DEFAULT 'card',
                  invoice_id INTEGER,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, completed_at TIMESTAMP,
                  FOREIGN KEY(user_id) REFERENCES users(id),
                  FOREIGN KEY(plan_id) REFERENCES plans(id))''')
    c.execute('''CREATE TABLE IF NOT EXISTS referrals
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  referrer_id INTEGER, referred_id INTEGER, plan_id INTEGER,
                  amount INTEGER DEFAULT 25, status TEXT DEFAULT 'pending',
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, paid_at TIMESTAMP,
                  FOREIGN KEY(referrer_id) REFERENCES users(telegram_id),
                  FOREIGN KEY(referred_id) REFERENCES users(telegram_id))''')
    c.execute('''CREATE TABLE IF NOT EXISTS promo_subscriptions
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  user_id INTEGER, plan_id INTEGER, duration_days INTEGER,
                  issued_by INTEGER, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  activated_at TIMESTAMP,
                  FOREIGN KEY(user_id) REFERENCES users(id),
                  FOREIGN KEY(issued_by) REFERENCES users(telegram_id))''')
    c.execute('''CREATE TABLE IF NOT EXISTS withdrawal_captcha
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  user_id INTEGER, amount INTEGER, captcha_text TEXT,
                  captcha_answer TEXT, options TEXT,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  FOREIGN KEY(user_id) REFERENCES users(id))''')
    c.execute('''CREATE TABLE IF NOT EXISTS promo_codes
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  code TEXT UNIQUE NOT NULL,
                  discount_type TEXT NOT NULL DEFAULT 'percent',
                  discount_value INTEGER NOT NULL,
                  plan_id INTEGER,
                  uses_left INTEGER,
                  uses_total INTEGER DEFAULT 0,
                  expires TEXT,
                  created_by INTEGER,
                  is_active INTEGER DEFAULT 1,
                  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
    c.execute('''CREATE TABLE IF NOT EXISTS promo_code_uses
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  code_id INTEGER NOT NULL,
                  user_id INTEGER NOT NULL,
                  plan_id INTEGER,
                  discount_amount INTEGER,
                  used_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                  FOREIGN KEY(code_id) REFERENCES promo_codes(id))''')
    conn.commit()

    # ── Миграции: добавляем колонки если их нет (для старых БД) ──────────────
    migrations = [
        ("users",   "balance",       "INTEGER DEFAULT 0"),
        ("users",   "promo_balance", "INTEGER DEFAULT 0"),
        ("users",   "terms_accepted","INTEGER DEFAULT 0"),
        ("users",   "referral_code", "TEXT"),
        ("users",   "referred_by",   "INTEGER"),
        ("payments","payment_type",  "TEXT DEFAULT 'card'"),
        ("payments","invoice_id",    "INTEGER"),
        ("plans",   "server_count",  "INTEGER DEFAULT 10"),
    ]
    for table, column, col_def in migrations:
        try:
            conn2 = sqlite3.connect('izlom_vpn.db')
            conn2.execute(f"ALTER TABLE {table} ADD COLUMN {column} {col_def}")
            conn2.commit(); conn2.close()
            logger.info(f"Миграция: добавлена колонка {table}.{column}")
        except Exception:
            pass  # Колонка уже существует — OK

    conn.close()
    logger.info("✅ БД инициализирована (данные сохранены)")


