def generate_subscription_key(user_id, plan_id):
    unique = f"{user_id}_{plan_id}_{int(time.time())}_{uuid.uuid4().hex[:8]}"
    h = hashlib.md5(unique.encode()).hexdigest()
    return f"{h[:8]}-{uuid.uuid4().hex[:4]}-{uuid.uuid4().hex[:4]}-{uuid.uuid4().hex[:4]}-{uuid.uuid4().hex[:12]}"

def generate_referral_code(telegram_id):
    return hashlib.md5(f"{telegram_id}_{int(time.time())}".encode()).hexdigest()[:8].upper()

def create_subscription_on_site(user_id, plan_name, key, devices, price, sub_end):
    subscription_url = f"{SITE_DOMAIN}/api/get/{key}"
    try:
        resp = requests.post(
            f"{SITE_DOMAIN}/api/create.php",
            data={
                'secret': SITE_API_SECRET,
                'user_id': user_id,
                'plan': plan_name,
                'key': key,
                'devices': devices,
                'price': price,
                'expires': sub_end.strftime('%Y-%m-%d %H:%M:%S'),
            },
            timeout=8
        )
        if resp.status_code == 200:
            logger.info(f"Сайт зарегистрировал подписку: {key}")
        else:
            logger.warning(f"Сайт вернул {resp.status_code} для ключа {key}")
    except Exception as e:
        logger.error(f"Ошибка регистрации подписки на сайте: {e}")
    return subscription_url

def create_yoomoney_payment_link(amount, label, description):
    params = {
        "receiver": YOOMONEY_WALLET,
        "quickpay-form": "shop",
        "targets": description,
        "paymentType": "SB",
        "sum": amount,
        "label": label,
        "successURL": "https://t.me/izlomc_bot"
    }
    qs = "&".join(f"{k}={v}" for k, v in params.items())
    return f"https://yoomoney.ru/quickpay/confirm.xml?{qs}"

def check_yoomoney_payment(label):
    try:
        resp = requests.post(
            "https://yoomoney.ru/api/operation-history",
            headers={"Authorization": f"Bearer {YOOMONEY_TOKEN}",
                     "Content-Type": "application/x-www-form-urlencoded"},
            data={"records": 20, "type": "deposition"}
        )
        if resp.status_code == 200:
            for op in resp.json().get("operations", []):
                if op.get("label") == label and op.get("status") == "success":
                    return {"found": True, "amount": op.get("amount")}
        return {"found": False}
    except Exception as e:
        logger.error(f"Ошибка проверки платежа: {e}")
        return {"found": False}

# ─────────────────────────── CRYPTOBOT API ───────────────────────────

def get_usdt_rate() -> float:
    """Получает актуальный курс USDT через CryptoBot."""
    try:
        resp = requests.get(
            f"{CRYPTOBOT_API}/getExchangeRates",
            headers={"Crypto-Pay-API-Token": CRYPTOBOT_TOKEN},
            timeout=5
        )
        if resp.status_code == 200:
            for r in resp.json().get("result", []):
                if r.get("source") == "USDT" and r.get("target") == "RUB":
                    return 1.0 / float(r["rate"])
    except Exception as e:
        logger.warning(f"Курс недоступен, используем дефолтный: {e}")
    return RUB_TO_USDT


def rub_to_usdt(rub_amount: int) -> str:
    rate = get_usdt_rate()
    usdt = round(rub_amount * rate, 2)
    return str(max(usdt, 0.01))


def create_cryptobot_invoice(amount_rub: int, label: str, description: str) -> dict:
    usdt_amount = rub_to_usdt(amount_rub)
    try:
        resp = requests.post(
            f"{CRYPTOBOT_API}/createInvoice",
            headers={"Crypto-Pay-API-Token": CRYPTOBOT_TOKEN},
            json={
                "currency_type": "crypto",
                "asset": "USDT",
                "amount": usdt_amount,
                "description": description,
                "payload": label,
                "allow_comments": False,
                "allow_anonymous": True,
                "expires_in": 3600,
            },
            timeout=10
        )
        data = resp.json()
        if data.get("ok") and data.get("result"):
            inv = data["result"]
            return {
                "ok": True,
                "pay_url": inv["pay_url"],
                "invoice_id": inv["invoice_id"],
                "usdt_amount": usdt_amount,
            }
        logger.error(f"CryptoBot createInvoice error: {data}")
        return {"ok": False}
    except Exception as e:
        logger.error(f"CryptoBot createInvoice exception: {e}")
        return {"ok": False}


def check_cryptobot_invoice(invoice_id: int) -> dict:
    try:
        resp = requests.get(
            f"{CRYPTOBOT_API}/getInvoices",
            headers={"Crypto-Pay-API-Token": CRYPTOBOT_TOKEN},
            params={"invoice_ids": str(invoice_id)},
            timeout=10
        )
        data = resp.json()
        if data.get("ok"):
            for inv in data.get("result", {}).get("items", []):
                if inv.get("invoice_id") == invoice_id and inv.get("status") == "paid":
                    return {"found": True}
        return {"found": False}
    except Exception as e:
        logger.error(f"CryptoBot check error: {e}")
        return {"found": False}


def do_activate(c, user_db_id, telegram_id, plan_id, plan_name, devices, price):
    key = generate_subscription_key(user_db_id, plan_id)
    end_date = datetime.now() + timedelta(days=30)
    page_url = create_subscription_on_site(telegram_id, plan_name, key, devices, price, end_date)
    sub_url = f"{SITE_DOMAIN}/api/sub/{key}/{key}.txt"
    c.execute('''UPDATE users SET plan_id=?, subscription_end=?, subscription_key=?, subscription_url=?
                 WHERE id=?''', (plan_id, end_date, key, page_url, user_db_id))
    return key, page_url, sub_url, end_date


def check_promo_code(code: str, user_telegram_id: int, plan_id: int):
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT * FROM promo_codes WHERE UPPER(code)=UPPER(?) AND is_active=1", (code,))
    row = c.fetchone()
    if not row:
        conn.close()
        return {'ok': False, 'error': '❌ Промокод не найден или уже недействителен'}
    col = ['id','code','discount_type','discount_value','plan_id','uses_left',
           'uses_total','expires','created_by','is_active','created_at']
    promo = dict(zip(col, row))
    if promo['expires']:
        if datetime.strptime(promo['expires'], '%Y-%m-%d') < datetime.now():
            conn.close()
            return {'ok': False, 'error': '❌ Срок действия промокода истёк'}
    if promo['uses_left'] is not None and promo['uses_left'] <= 0:
        conn.close()
        return {'ok': False, 'error': '❌ Промокод исчерпан'}
    if promo['plan_id'] and promo['plan_id'] != plan_id:
        c.execute("SELECT name FROM plans WHERE id=?", (promo['plan_id'],))
        r = c.fetchone()
        plan_name = r[0] if r else '?'
        conn.close()
        return {'ok': False, 'error': f'❌ Промокод действует только для тарифа «{plan_name}»'}
    c.execute('''SELECT COUNT(*) FROM promo_code_uses WHERE code_id=? AND user_id=?''',
              (promo['id'], user_telegram_id))
    already = c.fetchone()[0]
    conn.close()
    if already > 0:
        return {'ok': False, 'error': '❌ Вы уже использовали этот промокод'}
    c2 = sqlite3.connect('izlom_vpn.db')
    cur = c2.cursor()
    cur.execute("SELECT price FROM plans WHERE id=?", (plan_id,))
    plan_row = cur.fetchone()
    c2.close()
    if not plan_row:
        return {'ok': False, 'error': '❌ Тариф не найден'}
    original = plan_row[0]
    if promo['discount_type'] == 'percent':
        discount = int(original * promo['discount_value'] / 100)
    else:
        discount = promo['discount_value']
    final = max(1, original - discount)
    return {
        'ok': True,
        'code_id': promo['id'],
        'code': promo['code'].upper(),
        'discount_type': promo['discount_type'],
        'discount_value': promo['discount_value'],
        'original_price': original,
        'discount_amount': discount,
        'final_price': final,
    }

def apply_promo_code(code_id: int, user_telegram_id: int, plan_id: int, discount_amount: int):
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute('''INSERT INTO promo_code_uses (code_id, user_id, plan_id, discount_amount)
                 VALUES (?,?,?,?)''', (code_id, user_telegram_id, plan_id, discount_amount))
    c.execute('''UPDATE promo_codes SET uses_total=uses_total+1,
                 uses_left=CASE WHEN uses_left IS NOT NULL THEN uses_left-1 ELSE NULL END
                 WHERE id=?''', (code_id,))
    conn.commit()
    conn.close()

def format_promo_info(promo: dict) -> str:
    if promo['discount_type'] == 'percent':
        disc_str = f"{promo['discount_value']}%"
    else:
        disc_str = f"{promo['discount_value']} ₽"
    return (f"🎟 *Промокод:* `{promo['code']}`\n"
            f"💸 *Скидка:* {disc_str} (−{promo['discount_amount']} ₽)\n"
            f"~~{promo['original_price']} ₽~~ → *{promo['final_price']} ₽*")

def check_promo_code_by_id(code_id: int, user_telegram_id: int, plan_id: int):
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT * FROM promo_codes WHERE id=? AND is_active=1", (code_id,))
    row = c.fetchone()
    conn.close()
    if not row:
        return {'ok': False, 'error': '❌ Промокод больше недействителен'}
    col = ['id','code','discount_type','discount_value','plan_id','uses_left',
           'uses_total','expires','created_by','is_active','created_at']
    promo = dict(zip(col, row))
    if promo['uses_left'] is not None and promo['uses_left'] <= 0:
        return {'ok': False, 'error': '❌ Промокод исчерпан'}
    conn2 = sqlite3.connect('izlom_vpn.db')
    c2 = conn2.cursor()
    c2.execute("SELECT COUNT(*) FROM promo_code_uses WHERE code_id=? AND user_id=?",
               (code_id, user_telegram_id))
    already = c2.fetchone()[0]
    conn2.close()
    if already:
        return {'ok': False, 'error': '❌ Вы уже использовали этот промокод'}
    return {'ok': True}


def payment_checker_thread():
    while True:
        try:
            conn = sqlite3.connect('izlom_vpn.db')
            c = conn.cursor()
            c.execute('''SELECT p.id, p.user_id, p.plan_id, p.amount, p.label,
                                u.telegram_id, pl.name, pl.devices, pl.price,
                                p.payment_type, p.invoice_id
                         FROM payments p
                         JOIN users u ON p.user_id = u.id
                         JOIN plans pl ON p.plan_id = pl.id
                         WHERE p.status='pending' AND p.label IS NOT NULL
                           AND p.created_at > datetime('now', '-1 day')''')
            for row in c.fetchall():
                pay_id, user_db_id, plan_id, amount, label, tg_id, plan_name, devices, price, pay_type, invoice_id = row

                # Определяем способ оплаты и проверяем
                if pay_type and pay_type.startswith('crypto'):
                    if not invoice_id:
                        continue
                    result = check_cryptobot_invoice(invoice_id)
                else:
                    result = check_yoomoney_payment(label)

                if not result["found"]:
                    continue

                key, page_url, sub_url, end_date = do_activate(c, user_db_id, tg_id, plan_id, plan_name, devices, price)
                c.execute("UPDATE payments SET status='completed', completed_at=? WHERE id=?",
                          (datetime.now(), pay_id))
                conn.commit()
                c.execute("SELECT referred_by FROM users WHERE id=?", (user_db_id,))
                ref = c.fetchone()
                if ref and ref[0]:
                    process_referral_bonus(ref[0], tg_id, plan_id, amount)
                proxy_link = get_proxy_link_for_user(tg_id)
                markup = types.InlineKeyboardMarkup(row_width=1)
                markup.add(
                    types.InlineKeyboardButton("🚀 Подключиться", url=page_url),
                    types.InlineKeyboardButton("🔓 Обход блокировки Telegram", url=proxy_link),
                    types.InlineKeyboardButton("🔑 Моя подписка", callback_data="my_sub"),
                )
                pay_icon = "₿" if (pay_type and pay_type.startswith('crypto')) else "💳"
                receipt = generate_receipt_text(tg_id, plan_name, amount, label, end_date,
                                                payment_type="Криптовалюта (USDT)" if (pay_type and pay_type.startswith('crypto')) else "Банковская карта")
                try:
                    bot.send_message(tg_id,
                        f"🎉 *ПЛАТЕЖ ПРОШЕЛ УСПЕШНО!* 🎉\n\n"
                        f"📋 *Тариф:* {plan_name}\n"
                        f"💰 *Сумма:* {amount} ₽\n"
                        f"{pay_icon} *Способ:* {'Криптовалюта (USDT)' if (pay_type and pay_type.startswith('crypto')) else 'Банковская карта'}\n"
                        f"📅 *Активен до:* {end_date.strftime('%d.%m.%Y')}\n\n"
                        f"👇 Нажмите кнопку ниже для подключения:",
                        parse_mode='Markdown', reply_markup=markup)
                    bot.send_message(tg_id, receipt, parse_mode='Markdown')
                    send_receipt_pdf(tg_id, tg_id, plan_name, amount, label, end_date,
                                     payment_type="Криптовалюта (USDT)" if (pay_type and pay_type.startswith('crypto')) else "Банковская карта")
                except Exception as e:
                    logger.error(f"Не удалось отправить сообщение {tg_id}: {e}")
            conn.close()
        except Exception as e:
            logger.error(f"Ошибка checker: {e}")
        time.sleep(30)

