@bot.callback_query_handler(func=lambda c: c.data == "withdraw")
@require_subscription
def withdraw_request(call):
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT promo_balance FROM users WHERE telegram_id=?", (call.from_user.id,))
    balance = c.fetchone()[0]; conn.close()
    if balance < 1200:
        bot.answer_callback_query(call.id, f"❌ Минимум 1200 ₽. У вас {balance} ₽"); return
    fruits = ['🍎 яблоко', '🍌 банан', '🍊 апельсин', '🍇 виноград', '🍓 клубника', '🍉 арбуз']
    correct = random.choice(fruits)
    options = random.sample(fruits, 4)
    if correct not in options:
        options[0] = correct; random.shuffle(options)
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("INSERT INTO withdrawal_captcha (user_id,amount,captcha_text,captcha_answer,options) VALUES (?,?,?,?,?)",
              (call.from_user.id, balance, correct.split()[1], correct, json.dumps(options)))
    conn.commit(); conn.close()
    markup = types.InlineKeyboardMarkup(row_width=2)
    for opt in options:
        markup.add(types.InlineKeyboardButton(opt, callback_data=f"captcha_{opt.split()[1]}"))
    bot.send_message(call.message.chat.id,
        f"🔐 *Подтверждение вывода*\n\nСумма: *{balance} ₽*\n\nВыберите правильный фрукт:",
        parse_mode='Markdown', reply_markup=markup)
    bot.answer_callback_query(call.id)


@bot.callback_query_handler(func=lambda c: c.data.startswith('captcha_'))
def process_captcha(call):
    answer = call.data.replace('captcha_', '')
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT id, amount, captcha_answer FROM withdrawal_captcha WHERE user_id=? ORDER BY created_at DESC LIMIT 1",
              (call.from_user.id,))
    captcha = c.fetchone()
    if not captcha:
        conn.close(); bot.answer_callback_query(call.id, "❌ Капча устарела"); return
    cap_id, amount, correct = captcha
    if answer != correct:
        conn.close(); bot.answer_callback_query(call.id, "❌ Неправильно!"); return
    c.execute("UPDATE users SET balance=balance+promo_balance, promo_balance=0 WHERE telegram_id=?",
              (call.from_user.id,))
    c.execute("DELETE FROM withdrawal_captcha WHERE id=?", (cap_id,))
    conn.commit(); conn.close()
    bot.edit_message_text(
        f"✅ *Заявка на вывод принята!*\n\n"
        f"💰 Сумма: *{amount} ₽*\n"
        f"📅 Обработка: до 24 часов\n"
        f"Средства поступят на вашу банковскую карту.",
        call.message.chat.id, call.message.message_id, parse_mode='Markdown')
    bot.answer_callback_query(call.id, "✅ Капча пройдена!")


