@bot.callback_query_handler(func=lambda c: c.data.startswith('check_'))
def manual_check(call):
    label = call.data.replace('check_', '')
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute('''SELECT p.status, u.id, pl.name, pl.id, p.amount, u.telegram_id, pl.devices, pl.price, p.payment_type, p.invoice_id
                 FROM payments p JOIN users u ON p.user_id=u.id JOIN plans pl ON p.plan_id=pl.id
                 WHERE p.label=?''', (label,))
    result = c.fetchone()
    if not result:
        conn.close(); bot.answer_callback_query(call.id, "❌ Платеж не найден"); return
    status, user_db_id, plan_name, plan_id, amount, tg_id, devices, price, pay_type, invoice_id = result
    if status == 'completed':
        conn.close(); bot.answer_callback_query(call.id, "✅ Подписка уже активна!"); return

    # Проверяем в зависимости от типа платежа
    is_crypto = pay_type and pay_type.startswith('crypto')
    if is_crypto:
        if not invoice_id:
            conn.close(); bot.answer_callback_query(call.id, "❌ Ошибка: нет invoice_id"); return
        found = check_cryptobot_invoice(invoice_id)
    else:
        found = check_yoomoney_payment(label)

    if found["found"]:
        key, page_url, sub_url, end_date = do_activate(c, user_db_id, tg_id, plan_id, plan_name, devices, price)
        c.execute("UPDATE payments SET status='completed', completed_at=? WHERE label=?",
                  (datetime.now(), label))
        conn.commit()
        if pay_type and 'promo_' in pay_type:
            try:
                code_id = int(pay_type.split('_')[-1])
                apply_promo_code(code_id, tg_id, plan_id, price - amount)
            except Exception as e:
                logger.error(f"Ошибка фиксации промокода: {e}")
        c.execute("SELECT referred_by FROM users WHERE id=?", (user_db_id,))
        ref = c.fetchone()
        if ref and ref[0]: process_referral_bonus(ref[0], tg_id, plan_id, amount)
        conn.close()
        proxy_link = get_proxy_link_for_user(tg_id)
        markup = types.InlineKeyboardMarkup(row_width=1)
        markup.add(
            types.InlineKeyboardButton("🚀 Подключиться", url=page_url),
            types.InlineKeyboardButton("🔓 Обход блокировки Telegram", url=proxy_link),
            types.InlineKeyboardButton("🔑 Моя подписка", callback_data="my_sub"),
        )
        pay_label = "Криптовалюта (USDT)" if is_crypto else "Банковская карта"
        bot.send_message(call.message.chat.id,
            f"🎉 *ПЛАТЕЖ ПРОШЕЛ УСПЕШНО!* 🎉\n\n"
            f"📋 *Тариф:* {plan_name}\n"
            f"💰 *Сумма:* {amount} ₽\n"
            f"{'₿' if is_crypto else '💳'} *Способ:* {pay_label}\n"
            f"📅 *До:* {end_date.strftime('%d.%m.%Y')}\n\n"
            f"Нажмите «Подключиться» для активации VPN:",
            parse_mode='Markdown', reply_markup=markup)
        receipt = generate_receipt_text(tg_id, plan_name, amount, label, end_date, payment_type=pay_label)
        bot.send_message(call.message.chat.id, receipt, parse_mode='Markdown')
        send_receipt_pdf(call.message.chat.id, tg_id, plan_name, amount, label, end_date, payment_type=pay_label)
        bot.answer_callback_query(call.id, "✅ Подписка активирована!")
    else:
        conn.close()
        bot.answer_callback_query(call.id, "⏳ Платеж ещё не найден, подождите...")


