def process_admin_promo(message):
    if message.from_user.id not in ADMIN_IDS: return
    try:
        tg_id_str, plan_name = message.text.strip().split()
        tg_id = int(tg_id_str)
    except:
        bot.send_message(message.chat.id, "❌ Неверный формат. Пример: `123456789 Pro`", parse_mode='Markdown')
        return
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT id, price, devices FROM plans WHERE name=?", (plan_name,))
    plan = c.fetchone()
    if not plan:
        bot.send_message(message.chat.id, f"❌ Тариф «{plan_name}» не найден"); conn.close(); return
    plan_id, price, devices = plan
    c.execute("SELECT id FROM users WHERE telegram_id=?", (tg_id,))
    user = c.fetchone()
    if not user:
        bot.send_message(message.chat.id, f"❌ Пользователь {tg_id} не найден"); conn.close(); return
    user_db_id = user[0]
    key, page_url, sub_url, end_date = do_activate(c, user_db_id, tg_id, plan_id, plan_name, devices, price)
    c.execute("INSERT INTO promo_subscriptions (user_id,plan_id,duration_days,issued_by) VALUES (?,?,?,?)",
              (user_db_id, plan_id, 30, message.from_user.id))
    conn.commit(); conn.close()
    label = f"promo_{tg_id}_{int(time.time())}"
    receipt = generate_receipt_text(tg_id, plan_name, 0, label, end_date, payment_type="Промо (бесплатно)")
    proxy_link = get_proxy_link_for_user(tg_id)
    try:
        markup_user = types.InlineKeyboardMarkup(row_width=1)
        markup_user.add(
            types.InlineKeyboardButton("🚀 Подключиться", url=page_url),
            types.InlineKeyboardButton("🔓 Обход блокировки Telegram", url=proxy_link),
        )
        bot.send_message(tg_id,
            f"🎁 *Вам выдана промо-подписка!*\n\n"
            f"📋 *Тариф:* {plan_name}\n"
            f"📅 *До:* {end_date.strftime('%d.%m.%Y')}\n\n"
            f"Нажмите кнопку ниже для подключения:",
            parse_mode='Markdown', reply_markup=markup_user)
        bot.send_message(tg_id, receipt, parse_mode='Markdown')
        send_receipt_pdf(tg_id, tg_id, plan_name, 0, label, end_date, payment_type="Промо (бесплатно)")
    except: pass
    bot.send_message(message.chat.id, f"✅ Промо {plan_name} выдан пользователю {tg_id}")


