def process_admin_broadcast(message):
    if message.from_user.id not in ADMIN_IDS: return
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT telegram_id FROM users"); users = c.fetchall(); conn.close()
    sent = failed = 0
    for (uid,) in users:
        try:
            bot.send_message(uid, message.text, parse_mode='Markdown'); sent += 1; time.sleep(0.05)
        except: failed += 1
    bot.send_message(message.chat.id, f"📊 Рассылка завершена: ✅ {sent} | ❌ {failed}")


