def process_admin_promo_create(message):
    if message.from_user.id not in ADMIN_IDS: return
    raw = message.text.strip().split()
    if len(raw) < 3:
        bot.send_message(message.chat.id,
            "❌ Минимум 3 параметра: `КОД ТИП ЗНАЧЕНИЕ`\nПример: `SAVE20 % 20`",
            parse_mode='Markdown'); return
    code = raw[0].upper()
    disc_type_raw = raw[1]
    try:
        disc_value = int(raw[2])
    except:
        bot.send_message(message.chat.id, "❌ Значение скидки должно быть числом"); return
    if disc_type_raw == '%':
        disc_type = 'percent'
        if not (1 <= disc_value <= 99):
            bot.send_message(message.chat.id, "❌ Процент должен быть от 1 до 99"); return
    elif disc_type_raw == 'r':
        disc_type = 'fixed'
        if disc_value < 1:
            bot.send_message(message.chat.id, "❌ Скидка в рублях должна быть > 0"); return
    else:
        bot.send_message(message.chat.id, "❌ Тип скидки: `%` или `r`", parse_mode='Markdown'); return
    plan_id = None
    if len(raw) > 3 and raw[3] not in ('all', '-'):
        conn = sqlite3.connect('izlom_vpn.db')
        c = conn.cursor()
        c.execute("SELECT id FROM plans WHERE name=?", (raw[3],))
        r = c.fetchone(); conn.close()
        if not r:
            bot.send_message(message.chat.id, f"❌ Тариф «{raw[3]}» не найден. Доступно: Pro, Бизнес"); return
        plan_id = r[0]
    uses_left = None
    if len(raw) > 4 and raw[4] not in ('inf', '-'):
        try: uses_left = int(raw[4])
        except: bot.send_message(message.chat.id, "❌ Лимит должен быть числом или `inf`", parse_mode='Markdown'); return
    expires = None
    if len(raw) > 5 and raw[5] != '-':
        try:
            datetime.strptime(raw[5], '%Y-%m-%d')
            expires = raw[5]
        except:
            bot.send_message(message.chat.id, "❌ Дата в формате ГГГГ-ММ-ДД"); return
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    try:
        c.execute('''INSERT INTO promo_codes (code, discount_type, discount_value, plan_id, uses_left, expires, created_by)
                     VALUES (?,?,?,?,?,?,?)''',
                  (code, disc_type, disc_value, plan_id, uses_left, expires, message.from_user.id))
        conn.commit()
    except sqlite3.IntegrityError:
        conn.close()
        bot.send_message(message.chat.id, f"❌ Промокод `{code}` уже существует", parse_mode='Markdown'); return
    conn.close()
    plan_str = f"только для «{raw[3]}»" if plan_id else "на все тарифы"
    lim_str = f"{uses_left} раз" if uses_left else "безлимит"
    exp_str = expires if expires else "бессрочно"
    disc_str = f"{disc_value}%" if disc_type == 'percent' else f"{disc_value} ₽"
    bot.send_message(message.chat.id,
        f"✅ *Промокод создан!*\n\n"
        f"🎟 Код: `{code}`\n"
        f"💸 Скидка: *{disc_str}*\n"
        f"📋 Тариф: {plan_str}\n"
        f"🔢 Лимит: {lim_str}\n"
        f"📅 Срок: {exp_str}",
        parse_mode='Markdown')


@bot.callback_query_handler(func=lambda c: c.data == "admin_promo_list")
def admin_promo_list(call):
    if call.from_user.id not in ADMIN_IDS:
        bot.answer_callback_query(call.id, "⛔ Доступ запрещен"); return
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute('''SELECT pc.code, pc.discount_type, pc.discount_value, pl.name,
                        pc.uses_left, pc.uses_total, pc.expires, pc.is_active
                 FROM promo_codes pc
                 LEFT JOIN plans pl ON pc.plan_id = pl.id
                 ORDER BY pc.is_active DESC, pc.created_at DESC
                 LIMIT 20''')
    rows = c.fetchall(); conn.close()
    if not rows:
        bot.send_message(call.message.chat.id, "📋 Промокодов пока нет")
        bot.answer_callback_query(call.id); return
    lines = ["📋 *ПРОМОКОДЫ* (последние 20):\n"]
    for code, dtype, dval, plan_name, uses_left, uses_total, expires, is_active in rows:
        status = "✅" if is_active else "❌"
        disc = f"{dval}%" if dtype == 'percent' else f"{dval}₽"
        lim = f"{uses_left} ост." if uses_left is not None else "∞"
        plan = plan_name or "все"
        exp = expires or "∞"
        lines.append(f"{status} `{code}` — {disc} | {plan} | {lim} / {uses_total}исп. | до {exp}")
    text = "\n".join(lines)
    if len(text) > 4000:
        text = text[:4000] + "\n..."
    bot.send_message(call.message.chat.id, text, parse_mode='Markdown')
    bot.answer_callback_query(call.id)


