def process_admin_promo_deactivate(message):
    if message.from_user.id not in ADMIN_IDS: return
    code = message.text.strip().upper()
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT id, is_active FROM promo_codes WHERE UPPER(code)=?", (code,))
    row = c.fetchone()
    if not row:
        conn.close()
        bot.send_message(message.chat.id, f"❌ Промокод `{code}` не найден", parse_mode='Markdown'); return
    code_id, is_active = row
    new_status = 0 if is_active else 1
    c.execute("UPDATE promo_codes SET is_active=? WHERE id=?", (new_status, code_id))
    conn.commit(); conn.close()
    action = "деактивирован 🔴" if new_status == 0 else "активирован ✅"
    bot.send_message(message.chat.id, f"🎟 Промокод `{code}` {action}", parse_mode='Markdown')


@bot.callback_query_handler(func=lambda c: c.data == "admin_promo_stats")
def admin_promo_stats(call):
    if call.from_user.id not in ADMIN_IDS:
        bot.answer_callback_query(call.id, "⛔ Доступ запрещен"); return
    conn = sqlite3.connect('izlom_vpn.db')
    c = conn.cursor()
    c.execute("SELECT COUNT(*) FROM promo_codes WHERE is_active=1"); active = c.fetchone()[0]
    c.execute("SELECT COUNT(*) FROM promo_codes WHERE is_active=0"); inactive = c.fetchone()[0]
    c.execute("SELECT COUNT(*) FROM promo_code_uses"); total_uses = c.fetchone()[0]
    c.execute("SELECT SUM(discount_amount) FROM promo_code_uses"); total_disc = c.fetchone()[0] or 0
    c.execute('''SELECT pc.code, COUNT(*) as cnt FROM promo_code_uses pcu
                 JOIN promo_codes pc ON pcu.code_id=pc.id
                 GROUP BY pc.code ORDER BY cnt DESC LIMIT 5''')
    top = c.fetchall(); conn.close()
    top_str = "\n".join(f"  `{code}` — {cnt} раз" for code, cnt in top) if top else "  нет данных"
    bot.send_message(call.message.chat.id,
        f"📊 *СТАТИСТИКА ПРОМОКОДОВ*\n\n"
        f"✅ Активных: {active}\n❌ Неактивных: {inactive}\n\n"
        f"🔢 Всего применений: {total_uses}\n"
        f"💸 Суммарная скидка: {total_disc} ₽\n\n"
        f"🏆 *Топ-5 промокодов:*\n{top_str}",
        parse_mode='Markdown')
    bot.answer_callback_query(call.id)


